125			parentCtx = context.Background()
126		}
127		ctx, cancel := context.WithCancel(parentCtx)
128		defer cancel()
129	
130		start := time.Now()
131		events, err := svc.Execute(ctx, req)
132		if err != nil {
133			return nil, fmt.Errorf("agent: execute: %w", err)
134		}
135	
136		final, toolCalls, routing := drainServiceEvents(events)
137		elapsed := time.Since(start)
138	
139		result := &Result{
140			Harness:    "agent",
141			Model:      model,
142			DurationMS: int(elapsed.Milliseconds()),
143			ToolCalls:  toolCalls,
144		}
145		if routing != nil {
146			result.Provider = routing.Provider
147			if routing.Model != "" {
148				result.Model = routing.Model
149			}
150		}
151		if final != nil {
152			// Normalized final text from the upstream harness (agent-32e8ff5e).
153			result.Output = final.FinalText
154			if final.Usage != nil {
155				// v0.9.1: Usage fields became *int so the API can distinguish
156				// "harness reported zero" from "harness didn't report". Treat
157				// nil as zero for DDx's int-valued result struct.
158				if final.Usage.InputTokens != nil {
159					result.InputTokens = *final.Usage.InputTokens
160				}
161				if final.Usage.OutputTokens != nil {
162					result.OutputTokens = *final.Usage.OutputTokens
163				}
164				if final.Usage.TotalTokens != nil {
165					result.Tokens = *final.Usage.TotalTokens
166				}
167			}
168			if final.CostUSD > 0 {
169				result.CostUSD = final.CostUSD
170			}
171			if final.RoutingActual != nil {
172				if result.Provider == "" {
173					result.Provider = final.RoutingActual.Provider
174				}
175				if final.RoutingActual.Model != "" {
176					result.Model = final.RoutingActual.Model
177				}
178			}
179			switch final.Status {
180			case "success", "":
181				// happy path; no-op
182			case "stalled":
183				result.ExitCode = 1
184				if final.Error != "" {
185					result.Error = "stalled: " + final.Error
186				} else {
187					result.Error = "stalled"
188				}
189			case "timed_out":
190				result.ExitCode = 1
191				result.Error = fmt.Sprintf("timeout after %v", wallClock.Round(time.Second))
192			case "cancelled":
193				result.ExitCode = 1
194				result.Error = "cancelled"
195			default:
196				result.ExitCode = 1
197				if final.Error != "" {
198					result.Error = final.Error
199				} else {
200					result.Error = final.Status
201				}
202			}
203			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
204			if final.SessionLogPath != "" {
205				// surface as session ID for downstream cross-reference (mirrors
206				// the legacy path's AgentSessionID population).
207				result.AgentSessionID = final.SessionLogPath
208			}
209		}
210	
211		promptSource := opts.PromptSource
212		if promptSource == "" {
213			if opts.PromptFile != "" {
214				promptSource = opts.PromptFile
215			} else {
216				promptSource = "inline"
217			}
218		}
219		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
220		r.recordRoutingOutcome(result, elapsed, opts)
221		return result, nil
222	}
