315	func resetNoopCompactionTimer(timer *time.Timer, limit time.Duration) (*time.Timer, <-chan time.Time) {
316		if limit <= 0 {
317			return timer, nil
318		}
319		if timer == nil {
320			timer = time.NewTimer(limit)
321			return timer, timer.C
322		}
323		stopNoopCompactionTimer(timer)
324		timer.Reset(limit)
325		return timer, timer.C
326	}
327	
328	func stopNoopCompactionTimer(timer *time.Timer) {
329		if timer == nil {
330			return
331		}
332		if !timer.Stop() {
333			select {
334			case <-timer.C:
335			default:
336			}
337		}
338	}
