340	type serviceNoopCompactionStreak struct {
341		start time.Time
342		count int
343	}
344	
345	func (s *serviceNoopCompactionStreak) record(ts time.Time, limit time.Duration) (string, bool) {
346		if limit <= 0 {
347			return "", false
348		}
349		if ts.IsZero() {
350			ts = time.Now().UTC()
351		}
352		started := false
353		if s.count == 0 {
354			s.start = ts
355			started = true
356		}
357		s.count++
358		elapsed := ts.Sub(s.start)
359		if elapsed < limit {
360			return "", started
361		}
362		return s.detail(elapsed, limit), started
363	}
364	
365	func (s *serviceNoopCompactionStreak) detail(elapsed, limit time.Duration) string {
366		if elapsed < limit {
367			elapsed = limit
368		}
369		return fmt.Sprintf("%s: time-based breaker fired after %s of consecutive no-op compaction events (limit %s, count %d)",
370			serviceNoopCompactionWallClockReason,
371			elapsed.Round(time.Second),
372			limit.Round(time.Second),
373			s.count)
374	}
375	
376	func (s *serviceNoopCompactionStreak) reset() {
377		s.start = time.Time{}
378		s.count = 0
379	}
380	
381	func eventTimestamp(ev agentlib.ServiceEvent) time.Time {
382		if !ev.Time.IsZero() {
383			return ev.Time
384		}
385		return time.Now().UTC()
386	}
