342	// harness and translates the result into a ProviderStatus. It is the
343	// production replacement for Runner.TestProviderConnectivity.
344	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
345		status := ProviderStatus{Reachable: false}
