378	// ValidateForExecuteLoopViaService is the production replacement for
379	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
380	// will pick at claim time). When harness is specified it confirms the harness
381	// exists in the service registry and (when model is set) attempts a
382	// ResolveRoute pre-flight.
383	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
384		if harnessName == "" {
385			return nil
386		}
387		if ctx == nil {
388			ctx = context.Background()
389		}
390		svc, err := NewServiceFromWorkDir(workDir)
391		if err != nil {
392			return fmt.Errorf("agent: build service: %w", err)
393		}
394		infos, err := svc.ListHarnesses(ctx)
395		if err != nil {
396			return fmt.Errorf("agent: list harnesses: %w", err)
397		}
398		found := false
399		for _, info := range infos {
400			if info.Name == harnessName {
401				found = true
402				if !info.Available {
403					return fmt.Errorf("agent: harness %s not available", harnessName)
404				}
405				break
406			}
407		}
408		if !found {
409			return fmt.Errorf("agent: unknown harness: %s", harnessName)
410		}
411	
412		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
413		// model is provided and provider/model-ref are not set.
414		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
415			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
416				Model:    model,
417				Harness:  harnessName,
418				ModelRef: modelRef,
419				Provider: provider,
420			}); err != nil {
421				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
422			}
423		}
424		return nil
425	}
