90	// executeOnService dispatches against a pre-built svc using the durable
91	// knobs from rcfg and per-invocation plumbing from runtime, then records
92	// one session-index row. It is the inlined replacement for the retired
93	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
94	func executeOnService(ctx context.Context, svc agentlib.DdxAgent, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
95		if svc == nil {
96			return nil, fmt.Errorf("agent: nil service")
97		}
98		if ctx == nil {
99			ctx = context.Background()
100		}
101	
102		promptText := runtime.Prompt
103		if runtime.PromptFile != "" {
104			data, err := readPromptFileBounded(runtime.PromptFile)
105			if err != nil {
106				return nil, fmt.Errorf("agent: read prompt file: %w", err)
107			}
108			promptText = string(data)
109		}
110		if promptText == "" {
111			return nil, fmt.Errorf("agent: prompt is required")
112		}
113	
114		wd := runtime.WorkDir
115		if wd == "" {
116			wd = workDir
117		}
118		if wd == "" {
119			wd, _ = os.Getwd()
120		}
121	
122		idle := rcfg.Timeout()
123		if idle <= 0 {
124			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
125		}
126		wall := rcfg.WallClock()
127		if wall <= 0 {
128			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
129		}
130	
131		sessionLogDir := runtime.SessionLogDirOverride
132		if sessionLogDir == "" {
133			sessionLogDir = rcfg.SessionLogDir()
134		}
135		if sessionLogDir == "" {
136			sessionLogDir = ResolveLogDir(workDir, "")
137		}
138	
139		harness := runtime.HarnessOverride
140		if harness == "" {
141			harness = rcfg.Harness()
142		}
143		if harness == "" && rcfg.Provider() != "" {
144			harness = rcfg.Provider()
145		}
146	
147		model := runtime.ModelOverride
148		if model == "" {
149			model = rcfg.Model()
150		}
151	
152		permissions := runtime.PermissionsOverride
153		if permissions == "" {
154			permissions = rcfg.Permissions()
155		}
156	
157		providerTimeout := ResolveProviderRequestTimeout(workDir, rcfg.Provider(), model, rcfg.ProviderRequestTimeout())
158	
159		req := agentlib.ServiceExecuteRequest{
160			Prompt:          promptText,
161			Model:           model,
162			Provider:        rcfg.Provider(),
163			Harness:         harness,
164			ModelRef:        rcfg.ModelRef(),
165			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
166			Permissions:     permissions,
167			WorkDir:         wd,
168			Timeout:         wall,
169			IdleTimeout:     idle,
170			ProviderTimeout: providerTimeout,
171			SessionLogDir:   sessionLogDir,
172			Metadata:        runtime.Correlation,
173		}
174	
175		cancelCtx, cancel := context.WithCancel(ctx)
176		defer cancel()
177	
178		start := time.Now().UTC()
179		events, err := svc.Execute(cancelCtx, req)
180		if err != nil {
181			return nil, fmt.Errorf("agent: execute: %w", err)
182		}
183	
184		final, toolCalls, routing := drainServiceEvents(events)
185		finishedAt := time.Now().UTC()
186		elapsed := finishedAt.Sub(start)
187	
188		result := &Result{
189			Harness:    harness,
190			Model:      model,
191			DurationMS: int(elapsed.Milliseconds()),
192			ToolCalls:  toolCalls,
193		}
194		if routing != nil {
195			result.Provider = routing.Provider
196			if routing.Model != "" {
197				result.Model = routing.Model
198			}
199			if routing.Harness != "" {
200				result.Harness = routing.Harness
201			}
202		}
203		if final != nil {
204			// Normalized final text from the upstream harness (agent-32e8ff5e);
205			// reviewer verdict extraction now parses this instead of raw stream
206			// frames (ddx-7bc0c8d5).
207			result.Output = final.FinalText
208			if final.Usage != nil {
209				// v0.9.1: Usage fields became *int (nullable).
210				if final.Usage.InputTokens != nil {
211					result.InputTokens = *final.Usage.InputTokens
212				}
213				if final.Usage.OutputTokens != nil {
214					result.OutputTokens = *final.Usage.OutputTokens
215				}
216				if final.Usage.TotalTokens != nil {
217					result.Tokens = *final.Usage.TotalTokens
218				}
219			}
220			if final.CostUSD > 0 {
221				result.CostUSD = final.CostUSD
222			}
223			if final.RoutingActual != nil {
224				if result.Provider == "" {
225					result.Provider = final.RoutingActual.Provider
226				}
227				if final.RoutingActual.Model != "" {
228					result.Model = final.RoutingActual.Model
229				}
230			}
231			switch final.Status {
232			case "success", "":
233				// happy path
234			case "stalled":
235				result.ExitCode = 1
236				if final.Error != "" {
237					result.Error = "stalled: " + final.Error
238				} else {
239					result.Error = "stalled"
240				}
241			case "timed_out":
242				result.ExitCode = 1
243				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
244			case "cancelled":
245				result.ExitCode = 1
246				result.Error = "cancelled"
247			default:
248				result.ExitCode = 1
249				if final.Error != "" {
250					result.Error = final.Error
251				} else {
252					result.Error = final.Status
253				}
254			}
255			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
256			if final.SessionLogPath != "" {
257				result.AgentSessionID = final.SessionLogPath
258			}
259		}
260		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
261			Harness:     harness,
262			Model:       model,
263			Provider:    rcfg.Provider(),
264			Effort:      rcfg.Effort(),
265			Correlation: runtime.Correlation,
266		}, result, start, finishedAt)
267		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
268		return result, nil
269	}
