271	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
272	// querying the service's ListHarnesses and (best-effort) the harness registry.
273	// It is the production replacement for Runner.Capabilities.
274	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
275		if ctx == nil {
276			ctx = context.Background()
277		}
278		svc, err := NewServiceFromWorkDir(workDir)
279		if err != nil {
280			return nil, fmt.Errorf("agent: build service: %w", err)
281		}
282		infos, err := svc.ListHarnesses(ctx)
283		if err != nil {
284			return nil, fmt.Errorf("agent: list harnesses: %w", err)
285		}
286		var info *agentlib.HarnessInfo
287		for i := range infos {
288			if infos[i].Name == harnessName {
289				info = &infos[i]
290				break
291			}
292		}
293		if info == nil {
294			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
295		}
296	
297		// Pull binary and reasoning-level metadata from the local registry — the
298		// service does not expose these directly today.
299		registry := newHarnessRegistry()
300		harness, _ := registry.Get(harnessName)
301	
302		caps := &HarnessCapabilities{
303			Harness:             info.Name,
304			Available:           info.Available,
305			Binary:              harness.Binary,
306			Path:                info.Path,
307			Surface:             harness.Surface,
308			CostClass:           info.CostClass,
309			IsLocal:             info.IsLocal,
310			ExactPinSupport:     info.ExactPinSupport,
311			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
312			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
313		}
314		if len(info.SupportedReasoning) > 0 {
315			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
316		} else if len(harness.ReasoningLevels) > 0 {
317			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
318		}
319	
320		if harness.DefaultModel != "" {
321			caps.Model = harness.DefaultModel
322			caps.Models = []string{harness.DefaultModel}
323		}
324	
325		// Profile mappings come from the local model catalog because the service
326		// does not surface a per-tier resolution endpoint today.
327		if harness.Surface != "" {
328			cat := BuiltinCatalog
329			for _, profile := range []string{"cheap", "fast", "smart"} {
330				if m, ok := cat.Resolve(profile, harness.Surface); ok {
331					if caps.ProfileMappings == nil {
332						caps.ProfileMappings = make(map[string]string)
333					}
334					caps.ProfileMappings[profile] = m
335				}
336			}
337		}
338		return caps, nil
339	}
