341	// TestProviderConnectivityViaService runs a HealthCheck against the named
342	// harness and translates the result into a ProviderStatus. It is the
343	// production replacement for Runner.TestProviderConnectivity.
344	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
345		status := ProviderStatus{Reachable: false}
346		if ctx == nil {
347			ctx = context.Background()
348		}
349		if harnessName == "virtual" || harnessName == "agent" {
350			status.Reachable = true
351			status.CreditsOK = true
352			return status
353		}
354		svc, err := NewServiceFromWorkDir(workDir)
355		if err != nil {
356			status.Error = err.Error()
357			return status
358		}
359		if timeout > 0 {
360			var cancel context.CancelFunc
361			ctx, cancel = context.WithTimeout(ctx, timeout)
362			defer cancel()
363		}
364		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
365			errStr := strings.ToLower(err.Error())
366			status.Error = err.Error()
367			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
368				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
369				status.CreditsOK = false
370			}
371			return status
372		}
373		status.Reachable = true
374		status.CreditsOK = true
375		return status
376	}
