63	// runAgentViaService is the new RunAgent dispatch path that drives the
64	// agent through agentlib.DdxAgent.Execute and drains the resulting event
65	// channel into a DDx Result. Old in-package code paths (RunAgent legacy
66	// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
67	// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
68	// stay in place; this function does NOT call them.
69	//
70	// Stall detection: we delegate to the agent's StallPolicy. The agent
71	// emits a stall event then a final event with Status="stalled".
72	func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
73		promptText, err := r.resolvePrompt(opts)
74		if err != nil {
75			return nil, err
76		}
77	
78		model := r.resolveModel(opts, "agent")
79		timeout := r.resolveTimeout(opts)
80		wallClock := r.resolveWallClock(opts)
81	
82		wd := opts.WorkDir
83		if wd == "" {
84			wd, _ = os.Getwd()
85		}
86	
87		// Construct the service. Reuses NewServiceFromWorkDir so provider/model
88		// routing data lands on the agent the same way every other DDx command
89		// constructs it (see serviceconfig.go).
90		svc, err := NewServiceFromWorkDir(wd)
91		if err != nil {
92			return nil, fmt.Errorf("agent: build service: %w", err)
93		}
94	
95		// Resolve where to write the per-request session log.
96		logDir := opts.SessionLogDir
97		if logDir == "" {
98			logDir = r.Config.SessionLogDir
99		}
100		if logDir == "" {
101			logDir = DefaultLogDir
102		}
103	
104		providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)
105	
106		// Build the public ExecuteRequest per CONTRACT-003.
107		req := agentlib.ServiceExecuteRequest{
108			Prompt:          promptText,
109			Model:           model,
110			Provider:        opts.Provider,
111			Harness:         "agent",
112			ModelRef:        opts.ModelRef,
113			Reasoning:       agentlib.Reasoning(opts.Effort),
114			Permissions:     opts.Permissions,
115			WorkDir:         wd,
116			Timeout:         wallClock,
117			IdleTimeout:     timeout,
118			ProviderTimeout: providerTimeout,
119			SessionLogDir:   logDir,
120			Metadata:        opts.Correlation,
121		}
122	
123		parentCtx := opts.Context
124		if parentCtx == nil {
125			parentCtx = context.Background()
126		}
127		ctx, cancel := context.WithCancel(parentCtx)
128		defer cancel()
129	
130		start := time.Now()
131		events, err := svc.Execute(ctx, req)
132		if err != nil {
133			return nil, fmt.Errorf("agent: execute: %w", err)
134		}
135	
136		final, toolCalls, routing := drainServiceEvents(events)
137		elapsed := time.Since(start)
138	
139		result := &Result{
140			Harness:    "agent",
141			Model:      model,
142			DurationMS: int(elapsed.Milliseconds()),
143			ToolCalls:  toolCalls,
144		}
145		if routing != nil {
146			result.Provider = routing.Provider
147			if routing.Model != "" {
148				result.Model = routing.Model
149			}
150		}
151		if final != nil {
152			// Normalized final text from the upstream harness (agent-32e8ff5e).
153			result.Output = final.FinalText
154			if final.Usage != nil {
155				// v0.9.1: Usage fields became *int so the API can distinguish
156				// "harness reported zero" from "harness didn't report". Treat
157				// nil as zero for DDx's int-valued result struct.
158				if final.Usage.InputTokens != nil {
159					result.InputTokens = *final.Usage.InputTokens
160				}
161				if final.Usage.OutputTokens != nil {
162					result.OutputTokens = *final.Usage.OutputTokens
163				}
164				if final.Usage.TotalTokens != nil {
165					result.Tokens = *final.Usage.TotalTokens
166				}
167			}
168			if final.CostUSD > 0 {
169				result.CostUSD = final.CostUSD
170			}
171			if final.RoutingActual != nil {
172				if result.Provider == "" {
173					result.Provider = final.RoutingActual.Provider
174				}
175				if final.RoutingActual.Model != "" {
176					result.Model = final.RoutingActual.Model
177				}
178			}
179			switch final.Status {
180			case "success", "":
181				// happy path; no-op
182			case "stalled":
183				result.ExitCode = 1
184				if final.Error != "" {
185					result.Error = "stalled: " + final.Error
186				} else {
187					result.Error = "stalled"
188				}
189			case "timed_out":
190				result.ExitCode = 1
191				result.Error = fmt.Sprintf("timeout after %v", wallClock.Round(time.Second))
192			case "cancelled":
193				result.ExitCode = 1
194				result.Error = "cancelled"
195			default:
196				result.ExitCode = 1
197				if final.Error != "" {
198					result.Error = final.Error
199				} else {
200					result.Error = final.Status
201				}
202			}
203			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
204			if final.SessionLogPath != "" {
205				// surface as session ID for downstream cross-reference (mirrors
206				// the legacy path's AgentSessionID population).
207				result.AgentSessionID = final.SessionLogPath
208			}
209		}
210	
211		promptSource := opts.PromptSource
212		if promptSource == "" {
213			if opts.PromptFile != "" {
214				promptSource = opts.PromptFile
215			} else {
216				promptSource = "inline"
217			}
218		}
219		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
220		r.recordRoutingOutcome(result, elapsed, opts)
221		return result, nil
222	}
