224	// drainServiceEvents reads service events and returns the final-event payload,
225	// the accumulated tool-call log, and the routing decision (when present in the
226	// routing_decision start event). A sustained run of no-op compaction telemetry
227	// is converted into a synthetic stalled final so execute-bead result details
228	// identify the time-based breaker instead of waiting for the outer wall clock.
229	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, []ToolCallEntry, *serviceRoutingActual) {
230		var final *serviceFinalData
231		var routing *serviceRoutingActual
232		var toolCalls []ToolCallEntry
233		pending := make(map[string]*ToolCallEntry) // call_id -> entry awaiting result
234		var noopCompactions serviceNoopCompactionStreak
235		var noopTimer *time.Timer
236		var noopTimerC <-chan time.Time
237		defer func() { stopNoopCompactionTimer(noopTimer) }()
238	
239		for {
240			select {
241			case <-noopTimerC:
242				detail := noopCompactions.detail(serviceNoopCompactionWallClockLimit, serviceNoopCompactionWallClockLimit)
243				return &serviceFinalData{
244					Status: "stalled",
245					Error:  detail,
246				}, toolCallsWithPending(toolCalls, pending), routing
247			case ev, ok := <-events:
248				if !ok {
249					// Any tool_call without a matching tool_result still gets recorded.
250					return final, toolCallsWithPending(toolCalls, pending), routing
251				}
252				if isNoopCompactionEvent(ev) {
253					detail, started := noopCompactions.record(eventTimestamp(ev), serviceNoopCompactionWallClockLimit)
254					if started {
255						noopTimer, noopTimerC = resetNoopCompactionTimer(noopTimer, serviceNoopCompactionWallClockLimit)
256					}
257					if detail != "" {
258						return &serviceFinalData{
259							Status: "stalled",
260							Error:  detail,
261						}, toolCallsWithPending(toolCalls, pending), routing
262					}
263					continue
264				}
265				if isServiceProgressEvent(ev) {
266					noopCompactions.reset()
267					stopNoopCompactionTimer(noopTimer)
268					noopTimerC = nil
269				}
270	
271				switch string(ev.Type) {
272				case serviceEventRoutingDecision:
273					var payload struct {
274						Harness  string `json:"harness"`
275						Provider string `json:"provider"`
276						Model    string `json:"model"`
277					}
278					if err := json.Unmarshal(ev.Data, &payload); err == nil {
279						routing = &serviceRoutingActual{
280							Harness:  payload.Harness,
281							Provider: payload.Provider,
282							Model:    payload.Model,
283						}
284					}
285				case serviceEventToolCall:
286					var data serviceToolCallData
287					if err := json.Unmarshal(ev.Data, &data); err == nil {
288						entry := &ToolCallEntry{
289							Tool:  data.Name,
290							Input: string(data.Input),
291						}
292						pending[data.ID] = entry
293					}
294				case serviceEventToolResult:
295					var data serviceToolResultData
296					if err := json.Unmarshal(ev.Data, &data); err == nil {
297						if entry, ok := pending[data.ID]; ok {
298							entry.Output = data.Output
299							entry.Error = data.Error
300							entry.Duration = int(data.DurationMS)
301							toolCalls = append(toolCalls, *entry)
302							delete(pending, data.ID)
303						}
304					}
305				case serviceEventFinal:
306					var data serviceFinalData
307					if err := json.Unmarshal(ev.Data, &data); err == nil {
308						final = &data
